solution_code:
#include <iostream>
#include <limits>

int main() {
    int n;
    if (!(std::cin >> n)) {
        std::cin.clear();
        std::cin.ignore(std::numeric_limits<std::streamsize>::max(), '\n');
        std::cout << "Error: not a number\n";
    } else if (n <= 0) {
        std::cout << "Error: must be positive\n";
    } else {
        std::cout << "Value: " << n << '\n';
    }
    return 0;
}

